import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

/**
 * Returns ALL restaurants linked to the current authenticated user via merchant_restaurants.
 * Used by community publishers (merchant / staff / supervisor) to associate posts
 * & recipes with a restaurant.
 */
export const useUserRestaurants = () => {
  const { user } = useAuth();

  return useQuery({
    queryKey: ["user-linked-restaurants", user?.id],
    queryFn: async () => {
      if (!user) return [] as Array<{ id: string; name: string; name_en: string | null; name_pt: string | null }>;
      const { data, error } = await supabase
        .from("merchant_restaurants")
        .select("restaurant_id, restaurants:restaurant_id(id, name, name_en, name_pt)")
        .eq("user_id", user.id);
      if (error) throw error;
      return (data || [])
        .map((row: any) => row.restaurants)
        .filter(Boolean) as Array<{ id: string; name: string; name_en: string | null; name_pt: string | null }>;
    },
    enabled: !!user,
    staleTime: 60_000,
  });
};
